export type MessageKey = keyof typeof messages.en | keyof typeof legacyMessages.en

export function translate(locale: Locale, key: MessageKey) {
  const currentMessages = messages[locale] as Partial<Record<MessageKey, string>>
  const fallbackMessages = legacyMessages[locale] as Partial<Record<MessageKey, string>>

  return currentMessages[key] ?? fallbackMessages[key] ?? String(key)
}

export function getExpenseTypeLabel(type: ExpenseType, locale: Locale) {
  const labels = {
    en: {
      Purchase: 'Purchase',
      Shipping: 'Shipping',
      Repair: 'Repair',
      Parts: 'Parts',
      Labor: 'Labor',
      Inspection: 'Inspection',
      Fees: 'Fees',
      Other: 'Other',
    },
    ar: {
      Purchase: 'شراء',
      Shipping: 'شحن',
      Repair: 'إصلاح',
      Parts: 'قطع',
      Labor: 'عمالة',
      Inspection: 'فحص',
      Fees: 'رسوم',
      Other: 'أخرى',
    },
  } as const

  return labels[locale][type]
}

